external_knowledge:
- Shining stars in attracting capital from abroad: countries that have performed well in attracting Foreign Direct Investment (FDI);
- Top spots in their respective regions: countries ranked highest in their region based on FDI;
- How much light are they emitting: the total value of FDI they have attracted;

sql:
SELECT category_name, description 
FROM indicator_categories 
WHERE category_id = 1;

SELECT country_name, region_id
FROM countries
ORDER BY population DESC;
